-- Seed products migrated from the original data/products.json.
-- Run after 03_storage.sql. Safe to re-run (upsert on id).

on conflict (id) do update set
  name=excluded.name, category=excluded.category, series=excluded.series,
  image_url=excluded.image_url, description=excluded.description, price=excluded.price,
  in_stock=excluded.in_stock, whatsapp_number=excluded.whatsapp_number,
  specs=excluded.specs, is_featured=excluded.is_featured, sort_order=excluded.sort_order;
